'use client';

import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { cn } from '@/lib/utils';
import { LayoutDashboard, Users, Video, BookOpen, GraduationCap, Trophy, LogOut, User as UserIcon, Shield } from 'lucide-react';
import { logout } from '@/lib/auth';
import { User } from '@/lib/types';

const navItems = [
    { name: 'Dashboard', href: '/', icon: LayoutDashboard, roles: ['SuperAdmin', 'DeptHead', 'Interviewer', 'null'] },
    { name: 'Candidates', href: '/candidates', icon: Users, roles: ['SuperAdmin', 'DeptHead', 'Interviewer'] },
    { name: 'Live Interview', href: '/interview', icon: Video, roles: ['Interviewer', 'DeptHead', 'SuperAdmin'] },
    { name: 'Question Bank', href: '/qbank', icon: BookOpen, roles: ['SuperAdmin', 'DeptHead', 'Interviewer'] },
    { name: 'Scoring Guide', href: '/guide', icon: GraduationCap, roles: ['SuperAdmin', 'DeptHead', 'Interviewer'] },
    { name: 'Scoreboard', href: '/scoreboard', icon: Trophy, roles: ['SuperAdmin', 'DeptHead', 'Interviewer'] },
    { name: 'Settings', href: '/settings', icon: Shield, roles: ['SuperAdmin'] },
];

export function Navigation({ user }: { user?: Partial<User> | null }) {
    const pathname = usePathname();

    if (!user) return null;

    return (
        <nav className="bg-slate-900 text-white h-screen w-64 fixed left-0 top-0 flex flex-col shadow-xl z-50">
            <div className="p-6 border-b border-slate-700">
                <h1 className="text-xl font-bold tracking-tight text-white">IEEE SBNU</h1>
                <p className="text-xs text-slate-400 mt-1 uppercase tracking-wider">Recruitment Portal</p>
                {user.departmentId && <div className="mt-2 text-[10px] bg-blue-900/50 p-1 rounded text-blue-200 border border-blue-800 text-center">{user.departmentId.replace('dept_', '').toUpperCase()} DEPT</div>}
            </div>

            <div className="flex-1 overflow-y-auto py-6 space-y-1">
                {navItems.filter(item => item.roles.includes(user.role || 'null')).map((item) => {
                    const isActive = pathname === item.href || (item.href !== '/' && pathname.startsWith(item.href));
                    return (
                        <Link
                            key={item.href}
                            href={item.href}
                            className={cn(
                                "flex items-center gap-3 px-6 py-3 text-sm font-medium transition-colors",
                                isActive
                                    ? "bg-blue-600 text-white border-r-4 border-white"
                                    : "text-slate-400 hover:bg-slate-800 hover:text-white"
                            )}
                        >
                            <item.icon size={18} />
                            {item.name}
                        </Link>
                    );
                })}
            </div>

            <div className="p-6 border-t border-slate-700 bg-slate-800/50">
                <div className="flex items-center gap-3 mb-4">
                    <div className="bg-slate-700 p-2 rounded-full">
                        <UserIcon size={16} className="text-slate-300" />
                    </div>
                    <div>
                        <div className="text-sm font-bold text-white">{user.name}</div>
                        <div className="text-xs text-slate-400 flex items-center gap-1">
                            <Shield size={10} /> {user.role}
                        </div>
                    </div>
                </div>
                <button
                    onClick={() => logout()}
                    className="w-full py-2 bg-red-900/30 text-red-400 border border-red-900/50 rounded flex items-center justify-center gap-2 text-xs font-bold hover:bg-red-900/50 hover:text-red-200 transition-all"
                >
                    <LogOut size={14} /> Sign Out
                </button>
            </div>
        </nav>
    );
}

